import React from 'react';

function CustomParallax({ scrollPercentage }) {
  return (
    <div className="Parallax">
      <div className="Layer1" style={{backgroundPositionY: -scrollPercentage * 0.2 + 'px'}}></div>
      <div className="Layer2" style={{backgroundPositionY: -scrollPercentage * 0.4 + 'px'}}></div>
      <div className="Layer3" style={{backgroundPositionY: -scrollPercentage * 0.6 + 'px'}}></div>
      <div className="Layer4" style={{backgroundPositionY: -scrollPercentage * 0.8 + 'px'}}></div>
      <div className="Layer5" style={{backgroundPositionY: -scrollPercentage * 1.0 + 'px'}}></div>
    </div>
  );
}

export default CustomParallax;
